using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class UploadController : ControllerBase
    {
        private const string UploadsDirectory = "wwwroot/uploads";

        [HttpPost("avatar")]
        public IActionResult UploadAvatar(IFormFile file)
        {
            if (file.Length > 10485760) // 10MB max file size
                return BadRequest("File too large.");

            var allowedMimeTypes = new[] { "image/jpeg", "image/png", "application/pdf", "application/vnd.openxmlformats-officedocument.wordprocessingml.document", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet", "application/vnd.ms-excel" };
            if (!allowedMimeTypes.Contains(file.ContentType))
                return BadRequest("Invalid file type.");

            var fileName = Path.GetFileName(file.FileName);
            var filePath = Path.Combine(UploadsDirectory, fileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                file.CopyTo(stream);
            }

            return Ok(new { path = $"/uploads/{fileName}" });
        }

